import java.util.Scanner;public class ExercicioImposto {    public static void main(String[] args) {        Scanner inputSalario = new Scanner(System.in);        System.out.println("Qual seu salario mensal? R$");        double salarioMensal = inputSalario.nextDouble();        double impostoSalarioMensal = (salarioMensal * 9) / 100;        double salarioAnual = (salarioMensal * 12);        double impostoSalarioAnual = impostoSalarioMensal * 12;        System.out.println("Seu salario mensal é " + salarioMensal + "R$ e tu paga " + impostoSalarioMensal + "R$ de " +                "imposto nele");        System.out.println("Seu salario anual é " + salarioAnual + "R$ e você paga " + impostoSalarioAnual + "R$ de " +                "imposto nele");    }}